    if (CORREO == 1){
    	    $db = $_SESSION["db"];
	    $database = Cache::getCache('datosbase'.$db);

        require_once '../lib/Swift4/swift_required.php';
        $smtpServer= $_SESSION['smtpServer'];

        $email= $_SESSION['email'];
        $userName= $_SESSION['userName'];

        //echo $email;
//        $user= $_SESSION['emailUser'];
//        $pass= $_SESSION['emailPass'];
                    $user       = $database->smtpUser;
                    $pass       = $database->smtpPassword;


        //Create the Transport the call setUsername() and setPassword()
        $transport = Swift_SmtpTransport::newInstance($smtpServer, 465, 'ssl')
         ->setUsername($user)
         ->setPassword($pass);
        //Create the Mailer using your created Transport
        $mailer = Swift_Mailer::newInstance($transport);
        $date = date('d/m/Y');
        //Create a message
        if('EMAIL' != ''){
            $message = Swift_Message::newInstance("Mensaje de ORIGEN SUBJECT")
              ->setFrom($email)
                ->setTo('EMAIL');

            $message->setBody("MENSAJE", 'text/html');
            //Add alternative parts with addPart()
            $message->addPart("MENSAJE", 'text/plain');

            //Pass a variable name to the send() method
            if (!$mailer->send($message, $failures)){
                echo "Failures:";
                print_r($failures);
            }
            
                 // COPY TO SENT FOLDER
                 $server= $database->imapServer;
	         $serverImap = "{".$server.":143/imap/notls}";
     
                if ($server == 'imap.gmail.com') {
            	    $serverImap = '{imap.gmail.com:993/ssl}';
	            $stream = imap_open( $serverImap, $user, $pass);
		    imap_append($stream, '{imap.gmail.com:993/ssl}[GMail]/Enviados', $message->getHeaders()."\r\n".
									       $message->getTo()."\r\n".
									       $message->getSubject()."\r\n".
